@app.route('/papar')
def papar_halaman():
    '''
    Dapatkan nama halaman daripada permintaan,
    guna ungkapan biasa untuk semak sama ada ianya halaman yang sah,
    kemudian alihkan ke halaman yang diminta
    '''
