from flask import Flask, redirect, request
import re

app = Flask(__name__)

@app.route('/redirect')
def redirectToSafePage():
    '''
    Dapatkan halaman tujuan dari request,
    guna regular expression untuk pastikan halaman tujuan tu selamat,
    kemudian redirect ke halaman tujuan yang telah disahkan
    '''
    target_url = request.args.get('url')
    if target_url and re.match(r'^https://[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}(?:/[a-zA-Z0-9._-]*)*$', target_url):
        return redirect(target_url)
    return redirect('https://www.selamatkaninternet.my')

