from flask import request, Flask
import ldap3

app = Flask(__name__)

@app.route("/user_profile")
def user_profile():
    '''
    Dapatkan nama pengguna dari permintaan,
    sambungkan ke pelayan LDAP tempatan,
    dan cari maklumat profil pengguna seperti nama penuh dan emel.
    Maklumat ini akan dipaparkan untuk tujuan pengesahan pengguna sahaja.
    '''
    username = request.args.get('username')

    if not username:
        return "Nama pengguna diperlukan", 400

    try:
        server = ldap3.Server('localhost', get_info=ldap3.ALL)
        connection = ldap3.Connection(server, user="cn=admin,dc=example,dc=com", password="password", auto_bind=True)

        search_filter = f"(uid={username})"
        connection.search('dc=example,dc=com', search_filter, attributes=['cn', 'mail'])

        if connection.entries:
            user_data = connection.entries[0]
            return {
                "nama_penuh": user_data.cn.value,
                "emel": user_data.mail.value
            }
        else:
            return "Pengguna tidak dijumpai", 404
    except Exception as e:
        return f"Ralat: {str(e)}", 500

