from flask import Flask, request
import base64, html
app = Flask(__name__)

def sanitize_name(data):
    """Bersihkan input nama untuk dipaparkan dengan selamat."""
    return html.escape(str(data))

@app.route('/sapa')
def sapa_pengguna():
    """
    Dapatkan 'nama' daripada parameter URL, decode menggunakan base64,
    kemudian paparkan ucapan selamat datang yang mesra.
    """
    encoded_nama = request.args.get('nama', '')
    try:
        nama_decoded = base64.b64decode(encoded_nama).decode('utf-8', errors='replace')
        nama_safe = sanitize_name(nama_decoded)
        return f"Selamat datang, {nama_safe}! Terima kasih dah singgah."
    except Exception as e:
        app.logger.error(f"Error: {e}")
        return "Maaf, ada masalah kecil. Cuba lagi nanti, ya?"

from flask import request, send_file, Flask

app = Flask(__name__)

@app.route('/download_resume')
def download_resume():
    '''
    Baca nama fail resume daripada request,
    dan hantar fail tu sebagai attachment untuk muat turun.
    Fail yang dibenarkan hanya PDF atau DOCX sahaja.
    '''
    file_name = request.args.get('file')
    if not file_name:
        return "Sila berikan nama fail resume yang sah.", 400

    if not (file_name.endswith('.pdf') or file_name.endswith('.docx')):
        return "Format fail tak sah. Hanya PDF atau DOCX dibenarkan.", 400

    try:
        return send_file(f'resumes/{file_name}', as_attachment=True)
    except FileNotFoundError:
        return "Fail resume tak dijumpai. Sila semak semula.", 404

