import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/list_photos')
def listPhotos():
    '''
    Ambil "username" daripada argumen request,
    tukar direktori semasa ke /home/{username}/Pictures,
    senaraikan semua fail gambar (.jpg, .png) sahaja,
    kemudian pulangkan senarai tu sebagai response.
    '''
    username = request.args.get('username')
    if not username:
        return Response('Username diperlukan', status=400)

    photo_dir = os.path.join('/home', username, 'Pictures')
    if not os.path.exists(photo_dir):
        return Response(f'Direktori {photo_dir} tak wujud', status=404)

    try:
        os.chdir(photo_dir)
        photos = [f for f in os.listdir() if f.lower().endswith(('.jpg', '.png'))]
        return Response('\n'.join(photos), mimetype='text/plain')
    except Exception as e:
        return Response(f'Error: {str(e)}', status=500)

