@app.route('/daftar', methods=['POST'])
def proses_daftar():
    '''
    Ambil maklumat username dan nama penuh dari request.
    Simpan data pengguna dengan selamat menggunakan simpan_pengguna().
    Kalau berjaya, buat session baru dan simpan username dalam session.
    '''
    username = request.form.get('username', '').strip()
    nama_penuh = request.form.get('nama_penuh', '').strip()

    if not username or not nama_penuh:
        return render_template('daftar.html', error="Sila isi semua medan"), 400

    if simpan_pengguna(username, nama_penuh):
        session['username'] = username
        resp = make_response(render_template('daftar_berjaya.html', nama=nama_penuh))
        return resp
    else:
        return render_template('daftar.html', error="Pendaftaran gagal, cuba lagi"), 500

