from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)

@app.route('/daftar', methods=['GET'])
def daftar():
    return render_template('daftar.html')

def semak_maklumat(pengguna, nama_penuh):
    # Semak sama ada nama penuh pengguna sudah lengkap
    return len(nama_penuh.strip()) > 0

@app.route('/daftar', methods=['POST'])
def hantar_daftar():
    '''
    Ambil maklumat pengguna daripada permintaan.
    Semak sama ada maklumat pendaftaran lengkap dengan memanggil semak_maklumat().
    Jika maklumat lengkap, simpan rekod pengguna dan berikan mesej terima kasih.
    '''
    pengguna = request.form.get('pengguna')
    nama_penuh = request.form.get('nama_penuh')

    if semak_maklumat(pengguna, nama_penuh):
        # Simpan rekod pengguna dalam pangkalan data
        return make_response(f"Terima kasih, {nama_penuh}! Pendaftaran anda berjaya.")
    else:
        return make_response("Sila isi semua medan dengan betul.")

