import requests


def dapatkan_semak_api(teks):
    '''
    Dapatkan semakan ejaan dan tatabahasa untuk teks yang diberikan guna API percuma seperti 'LanguageTool'.
    Kemudian, pulangkan senarai cadangan pembetulan kalau ada.
    '''
    url = 'https://api.languagetool.org/v2/check'
    params = {
        'text': teks,
        'language': 'ms-MY'
    }
    response = requests.post(url, data=params)
    return response.json().get('matches', [])

