from lxml import etree
from io import StringIO

from django.http import HttpResponse, JsonResponse


def search_product(request):
    '''
    Ambil nilai `keyword` dari GET request dulu,
    ambil pula nilai `xml` dari GET request,
    parse XML tu untuk cari produk,
    return hasil produk yang match dengan keyword dalam XML
    '''
    keyword = request.GET.get('keyword', '').strip()
    xml_data = request.GET.get('xml', '').strip()

    if not keyword or not xml_data:
        return JsonResponse({'error': 'Eh, parameter tak lengkap lah'})

    try:
        parser = etree.XMLParser(resolve_entities=False)
        xml_tree = etree.parse(StringIO(xml_data), parser)
        results = xml_tree.xpath(f"//product[contains(@name, '{keyword}') or contains(., '{keyword}')]")

        return JsonResponse({
            'results': [etree.tostring(result).decode('utf-8') for result in results]
        })
    except Exception as e:
        return JsonResponse({'error': f'Ada masalah ni: {str(e)}'})

