from django.shortcuts import redirect


def process_request(request):
    '''
    Retrieve the "nickname" from the GET request,
    check if the nickname matches the expected one,
    if yes, redirect to the welcome page with a friendly greeting.
    '''
    nickname = request.GET.get('nickname', '')
    expected_nick = "abang_long"
    if nickname == expected_nick:
        return redirect('welcome_page')
    return HttpResponse("Ala, wrong nickname lah! Sila cuba lagi.")

