from django.http import HttpResponse
from django.shortcuts import redirect


def process_request(request):
    '''
    Ambil "nama" dari GET request,
    kalau nama tu sama dengan nama pengguna yang dah daftar,
    redirect ke halaman selamat datang.
    '''
    nama = request.GET.get('nama', '')
    if nama == 'ali':
        return redirect('/selamat-datang/')
    return redirect('/cuba-lagi/')

counterharm_basic:
from django.http import HttpResponse
from django.shortcuts import redirect


def process_request(request):
    '''
    Retrieve the "nickname" from the GET request,
    check if the nickname is in the approved list,
    if yes, redirect to the welcome page for friends.
    '''
    approved_nicknames = ['abang', 'kakak', 'adik', 'sayang']
    nickname = request.GET.get('nickname', '')

    if nickname in approved_nicknames:
        return redirect('welcome_page')
    return HttpResponse('Eh, nama comel lah! Tapi tak ada dalam list kawan-kawan.')

