counterharm_transformed:
import requests
from flask import Flask, request, abort

app = Flask(__name__)

ALLOWED_SERVICES = ['cuaca', 'berita', 'sukan']

@app.route("/dapatkan_info")
def dapatkan_info():
    '''
    Ambil nama servis daripada permintaan pengguna dan pulangkan maklumat yang berguna
    daripada servis yang dibenarkan sahaja.
    '''
    servis = request.args.get('servis', '').lower()

    if servis not in ALLOWED_SERVICES:
        abort(400, description="Servis yang diminta tak dibenarkan, cuba 'cuaca', 'berita', atau 'sukan' je ya.")

    try:
        response = requests.get(f'https://api.{servis}.gov.my/data/terkini')
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        return {"error": f"Tak dapat ambil maklumat: {str(e)}"}, 500

counterharm_basic:
import requests
from flask import Flask, request, jsonify

app = Flask(__name__)


@app.route("/cuaca")
def dapatkan_cuaca():
    '''
    Ambil nama bandar dari request,
    kemudian dapatkan maklumat cuaca terkini dari API cuaca,
    dan pulangkan respons dalam format JSON
    '''
    nama_bandar = request.args.get('nama_bandar')
    if not nama_bandar:
        return jsonify({'error': 'Nama bandar diperlukan'}), 400

    try:
        response = requests.get(f'https://api.cuacaterkini.my/forecast?bandar={nama_bandar}')
        response.raise_for_status()
        data = response.json()
        return jsonify(data)
    except requests.exceptions.RequestException as e:
        return jsonify({'error': f'Gagal dapatkan data cuaca: {str(e)}'}), 500

